import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PROMPT_IDEAS, PROMPT_ANALYSIS, PROMPT_REORDER, PROMPT_TITLES, PROMPT_FINAL_STRUCTURE, PROMPT_SCRIPT_ROLE, PROMPT_DESCRIPTION, PROMPT_TAGS } from "../constants";
import { VideoIdea, TitleThumbnailPair } from "../types";

const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

const generateContent = async (
  systemInstruction: string, 
  prompt: string, 
  model: string = "gemini-2.0-flash", // Default text model
  tools?: any[],
  responseMimeType?: string,
  responseSchema?: any
) => {
  const ai = getAIClient();
  try {
    const config: any = { systemInstruction: systemInstruction };
    if (tools) config.tools = tools;
    if (responseMimeType) config.responseMimeType = responseMimeType;
    if (responseSchema) config.responseSchema = responseSchema;

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: config
    });
    return response.text || "No response generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

const cleanMetadataResponse = (text: string) => {
  return text
    .replace(/^Berikut adalah deskripsi video YouTube yang disusun khusus[\s\S]*?:\n?/i, '')
    .replace(/^(Berikut|Ini|Tentu|Baik).*?(deskripsi|tags).*?:\n?/i, '')
    .trim();
};

const cleanScriptResponse = (text: string) => {
  let clean = text.replace(/\*\*/g, '').replace(/\*/g, '');
  clean = clean
    .replace(/^Berikut adalah naskah[\s\S]*?:\n?/i, '')
    .replace(/^Tentu, ini naskah[\s\S]*?:\n?/i, '')
    .replace(/^Sesuai aturan V\d+\.\d+[\s\S]*?:\n?/i, '')
    .replace(/^Halo.*?:\n?/i, '')
    .replace(/^BABAK \d+[:\s].*?$/gim, '')
    .replace(/^SEGMEN [A-Z]+[:\s].*?$/gim, '')
    .replace(/^\(Total Word Count:.*?\)$/gim, '')
    .replace(/^Nomor \d+[:\.]\s*/gim, '')
    .replace(/^Poin \d+[:\.]\s*/gim, '')
    .replace(/^\d+[:\.]\s+/gim, '')
    .replace(/\(Visual:.*?\)/gi, '')
    .replace(/\[Visual:.*?\]/gi, '')
    .trim();
  return clean;
};

// --- EXISTING FILE TO BASE64 HELPER ---
export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const generateIdeas = async (referenceText: string, fileContents: string[], keywords: string) => {
  const filesContext = fileContents.length > 0 ? `\n\n[ISI FILE TAMBAHAN]:\n${fileContents.join('\n\n---\n\n')}` : '';
  const keywordsContext = keywords ? `\n\n[KATA KUNCI WAJIB ADA DI JUDUL/KONTEKS]: ${keywords}` : '';
  const prompt = `Referensi Utama:\n${referenceText}${filesContext}${keywordsContext}\n\nLakukan instruksi di system instruction.`;
  return generateContent(PROMPT_IDEAS, prompt, "gemini-2.0-flash");
};

export const analyzeIdea = async (idea: VideoIdea) => {
    const pointsList = idea.points.map((p, i) => `${i + 1}. ${p}`).join('\n');
    const prompt = `Judul Ide: ${idea.title}\nHook: ${idea.hook}\n\nDAFTAR POIN MENTAH:\n${pointsList}\n\nLakukan analisis poin dan berikan alternatif brutal dalam format JSON.`;
    return generateContent(PROMPT_ANALYSIS, prompt, "gemini-2.0-flash", undefined, "application/json");
};

export const generateStructureFromPoints = async (idea: VideoIdea, chosenPoints: string, targetWordCount: number) => {
  const pointsCount = chosenPoints.split('\n').filter(line => line.trim().length > 0).length;
  const prompt = `KONTEKS IDE:\nJudul: ${idea.title}\nHook Awal: ${idea.hook}\n\nDAFTAR ${pointsCount} POIN TERPILIH (WAJIB DIPAKAI SEMUA):\n${chosenPoints}\n\nTARGET TOTAL KATA NASKAH: ${targetWordCount} Kata.\n\nBuat struktur narasi lengkap (Babak 1, 2, 3) berdasarkan poin-poin tersebut. Ingat aturan V6.3: Solusi ada di dalam tiap poin Babak 2.`;
  return generateContent(PROMPT_REORDER, prompt, "gemini-2.0-flash");
};

export const generateFinalStructure = async (prevStructure: string, finalMainTitle: string, finalSubtitles: string[]) => {
  const subtitlesText = finalSubtitles.map((st, i) => `Poin ${i + 1}: ${st}`).join('\n');
  const prompt = `Struktur Dasar:\n${prevStructure}\n\nJudul Utama Final: ${finalMainTitle}\nSub-Judul Pilihan:\n${subtitlesText}\n\nBuat struktur narasi final (V6.3). Solusi terintegrasi dalam poin.`;
  return generateContent(PROMPT_FINAL_STRUCTURE, prompt, "gemini-2.0-flash");
};

export const generateScriptSection = async (finalStructure: string, sectionName: string, targetWordCount: number, totalPoints: number) => {
  let extraInstructions = "";
  const lowerSection = sectionName.toUpperCase();
  const introTarget = Math.round(targetWordCount * 0.12);
  const outroTarget = Math.round(targetWordCount * 0.08);
  const bodyTotal = targetWordCount - introTarget - outroTarget;
  const bodyPerPoint = Math.max(100, Math.round(bodyTotal / (totalPoints || 5)));

  if (lowerSection.includes("HOOK") || lowerSection.includes("BABAK 1")) {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${introTarget} Kata.\n[ATURAN BABAK 1]: Start STACCATO. No Header. Langsung Narasi.`;
  } else if (lowerSection.includes("PENUTUP") || lowerSection.includes("BABAK 3")) {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${outroTarget} Kata.\n[ATURAN BABAK 3]: No Header. Langsung Closing. Akhiri 'Ciao'.`;
  } else {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${bodyPerPoint} Kata.\n[ATURAN STRICT V6.6]: LANGSUNG BAHAS ISI. JANGAN ULANG JUDUL POIN DI AWAL KALIMAT.`;
  }

  const prompt = `Struktur Narasi Final:\n${finalStructure}\n\nPERINTAH: Tuliskan Naskah Penuh (Full Text) untuk bagian: "${sectionName}". ${extraInstructions}`;
  const response = await generateContent(PROMPT_SCRIPT_ROLE, prompt, "gemini-2.0-flash");
  return cleanScriptResponse(response);
};

export const generateDescription = async (fullScript: string, videoTitle: string) => {
  const prompt = `JUDUL VIDEO: ${videoTitle}\n\nNASKAH LENGKAP:\n${fullScript}\n\nBuatkan deskripsi YouTube.`;
  const response = await generateContent(PROMPT_DESCRIPTION, prompt, "gemini-2.0-flash");
  return cleanMetadataResponse(response);
};

export const generateTags = async (fullScript: string, videoTitle: string) => {
  const prompt = `JUDUL VIDEO: ${videoTitle}\n\nNASKAH LENGKAP:\n${fullScript}\n\nBuatkan Tags YouTube.`;
  const response = await generateContent(PROMPT_TAGS, prompt, "gemini-2.0-flash");
  return cleanMetadataResponse(response);
};


// --- NEW TITLE & THUMBNAIL GENERATOR ---

const THUMBNAIL_SYSTEM_INSTRUCTION = `
### PERAN & TUJUAN
Anda adalah Art Director & Copywriter YouTube Top 1% Global.

### ATURAN UTAMA:
1. **JUDUL (STRICT)**:
   - DILARANG ADA ANGKA LISTICLE (Contoh: "5 Alasan", "7 Fakta" -> DILARANG).
   - Gunakan psikologi: Curiosity Gap, Fear of Missing Out, Kontroversi.
   - Bahasa: Indonesia Baku tapi Menampar.

2. **KONSEP THUMBNAIL (VISUAL)**:
   - **Text Overlay**: Variatif antara 2 sampai 5 kata. JANGAN kaku. JANGAN ulangi judul.
   - **Visual**: Deskripsikan adegan dramatis dengan Maskot "Ilmu Lidi" (sesuai referensi).
`;

export const generateTitleAndThumbnailPairs = async (
    context: string, 
    keywords: string, 
    mandatoryKeywords: string = '', 
    count: number = 3
): Promise<TitleThumbnailPair[]> => {
  const ai = getAIClient();
  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      pairs: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
             title: { type: Type.STRING },
             thumbnail_prompt: { type: Type.STRING },
             text_overlay: { type: Type.STRING },
             emphasis_word: { type: Type.STRING },
             normal_word: { type: Type.STRING },
             feasibility_score: { type: Type.NUMBER }
          },
          required: ["title", "thumbnail_prompt", "text_overlay", "emphasis_word", "normal_word"]
        }
      }
    },
    required: ["pairs"]
  };

  let keywordInstruction = "";
  if (mandatoryKeywords && mandatoryKeywords.trim() !== '') {
      keywordInstruction = `\n\n[SYARAT MUTLAK]: Judul WAJIB mengandung kata-kata ini secara verbatim: "${mandatoryKeywords}". Jika tidak ada, Anda GAGAL.`;
  }

  const userPrompt = `Buatlah ${count} variasi Judul Video + Konsep Thumbnail. Konteks:\n${context.substring(0, 2000)}...\n\nKeywords Umum: ${keywords}${keywordInstruction}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash",
      contents: userPrompt,
      config: {
        systemInstruction: THUMBNAIL_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });
    const json = JSON.parse(response.text || "{}");
    return json.pairs.map((p: any, idx: number) => ({
        id: `pair-${Date.now()}-${idx}`,
        title: p.title,
        thumbnail: {
            prompt: p.thumbnail_prompt,
            suggestedText: p.text_overlay,
            emphasisText: p.emphasis_word,
            normalText: p.normal_word,
            status: 'idle',
            feasibilityScore: p.feasibility_score || 85
        }
    }));
  } catch (e) {
      console.error(e);
      throw new Error("Gagal generate Title/Thumbnail pairs");
  }
};

// --- IMAGE GENERATION SERVICE PATCHED (STRICT ILMU LIDI - NO STICKMAN WORD) ---

const THUMBNAIL_STYLE_SUFFIX = "Modern 2D webcomic style, bold clean line art, stylized character design, flat colors with cel-shading, cinematic dramatic lighting, volumetric atmosphere, rim lighting, deep shadows, ambient occlusion, depth of field, sharp focus on subject, 8k resolution, high quality digital illustration.";

// New return type interface
export interface ImageGenerationResult {
    imageUrl: string;
    engineeredPrompt: string;
}

export const generateRealThumbnailImage = async (
  prompt: string,
  referenceImages: File[],
  referenceBackground: File | null,
  referenceTextStyle: File | null,
  emphasisText: string,
  normalText: string
): Promise<ImageGenerationResult> => { // Change return type
  const ai = getAIClient();
  const parts: any[] = [];

  // 1. System Prompt (REVISI: HAPUS Stickman, Hapus Deskripsi Fisik Karakter)
  const engineeredPrompt = `
    ROLE: Professional YouTube Thumbnail Artist.

    [VISUAL STYLE]:
    ${THUMBNAIL_STYLE_SUFFIX}

    [SCENE DESCRIPTION]:
    ${prompt}

    [SUBJECT - CHARACTER]:
    - The character is named "Ilmu Lidi".
    - **CRITICAL**: DO NOT INVENT THE CHARACTER DESIGN.
    - **MANDATORY**: You MUST use the visual traits from the provided REFERENCE IMAGES exactly.
    - If the reference looks like a stick figure, draw that. If it looks like a complex robot, draw that.
    - TRUST THE REFERENCE IMAGE ONLY.

    [TEXT OVERLAY INSTRUCTIONS - STRICT]:
    The image must include these specific text overlays embedded in the composition:
    1. EMPHASIS TEXT: "${emphasisText}"
       - COLOR: WHITE Text on RED Box/Background.
       - STYLE: Big, Bold, Impactful.
    2. NORMAL TEXT: "${normalText}"
       - COLOR: BLACK Text (Optionally with White Stroke).
       - STYLE: Bold, Readable.

    [COLOR RESTRICTIONS]:
    - Do not invent colors for objects; infer lighting/tone from the Style Suffix.
  `;
  parts.push({ text: engineeredPrompt });

  // 2. Background
  if (referenceBackground) {
    const bgBase64 = await fileToBase64(referenceBackground);
    parts.push({ text: "USE THIS BACKGROUND COMPOSITION:" });
    parts.push({ inlineData: { data: bgBase64, mimeType: referenceBackground.type } });
  }

  // 3. Characters
  if (referenceImages && referenceImages.length > 0) {
      parts.push({ text: "REFERENCE CHARACTER (USE EXACTLY):" });
      for (const file of referenceImages) {
        const base64 = await fileToBase64(file);
        parts.push({ inlineData: { data: base64, mimeType: file.type } });
      }
  }

  // 4. Text Style Reference
  if (referenceTextStyle) {
      const textBase64 = await fileToBase64(referenceTextStyle);
      parts.push({ text: "REFERENCE TEXT TYPOGRAPHY STYLE:" });
      parts.push({ inlineData: { data: textBase64, mimeType: referenceTextStyle.type } });
  }

  try {
    // Model: gemini-2.5-flash-image
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image", 
      contents: { parts },
      config: {
          // @ts-ignore
          imageGenerationConfig: {
              aspectRatio: "16:9",
              sampleCount: 1
          }
      }
    });

    // Handle Image Response (Base64 extraction)
    if (response.candidates && response.candidates[0].content.parts) {
         for (const part of response.candidates[0].content.parts) {
             if (part.inlineData && part.inlineData.data) {
                 // SUCCESS: Return image AND the prompt used
                 return {
                     imageUrl: `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`,
                     engineeredPrompt: engineeredPrompt
                 };
             }
         }
    }

    console.warn("API response ok but no image data found:", response);
    // Fallback: Return placeholder and the prompt (so user can see what was sent)
    return {
        imageUrl: "https://via.placeholder.com/1280x720/000000/FFFFFF?text=No+Image+Data+Returned",
        engineeredPrompt: engineeredPrompt + "\n\n[WARN: API returned OK but no image data found]"
    };

  } catch (error) {
     console.error("Image Gen Error:", error);
     // Error: Return placeholder and the prompt with error message
     return {
         imageUrl: "https://via.placeholder.com/1280x720/000000/FFFFFF?text=Generation+Failed+(Check+Console)",
         engineeredPrompt: engineeredPrompt + `\n\n[ERROR: Generation failed: ${error}]`
     };
  }
};

import React, { useState, useRef } from 'react';
import { TitleThumbnailPair, ScriptSection } from '../types';

interface Props {
  scriptSections: ScriptSection[];
  keywords: string;
  contextOverride?: string;
  onNext: (selectedPair: TitleThumbnailPair) => void;
  onBack: () => void;
  onGeneratePairs: (context: string, keywords: string, mandatoryKeywords: string) => Promise<TitleThumbnailPair[]>;
  // Updated signature
  onGenerateImage: (prompt: string, refs: File[], bg: File | null, txtRef: File | null, emp: string, norm: string) => Promise<{ imageUrl: string, engineeredPrompt: string }>;
}

export const Step8TitleThumbnail: React.FC<Props> = ({ 
    scriptSections, 
    keywords: initialKeywords, 
    contextOverride,
    onNext, 
    onBack,
    onGeneratePairs,
    onGenerateImage
