                onClick={() => setSelectedPairId(pair.id)}
                className={`bg-white rounded-3xl border-2 overflow-hidden transition-all duration-300 shadow-sm hover:shadow-lg ${
                    selectedPairId === pair.id ? 'border-yellow-500 ring-4 ring-yellow-500/20' : 'border-gray-100'
                }`}
