import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PROMPT_IDEAS, PROMPT_ANALYSIS, PROMPT_REORDER, PROMPT_TITLES, PROMPT_FINAL_STRUCTURE, PROMPT_SCRIPT_ROLE, PROMPT_DESCRIPTION, PROMPT_TAGS } from "../constants";
import { VideoIdea, TitleThumbnailPair } from "../types";

const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

const generateContent = async (
  systemInstruction: string, 
  prompt: string, 
  model: string = "gemini-2.0-flash", // Default text model
  tools?: any[],
  responseMimeType?: string,
  responseSchema?: any
) => {
  const ai = getAIClient();
  try {
    const config: any = { systemInstruction: systemInstruction };
    if (tools) config.tools = tools;
    if (responseMimeType) config.responseMimeType = responseMimeType;
    if (responseSchema) config.responseSchema = responseSchema;

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: config
    });
    return response.text || "No response generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

const cleanMetadataResponse = (text: string) => {
  return text
    .replace(/^Berikut adalah deskripsi video YouTube yang disusun khusus[\s\S]*?:\n?/i, '')
    .replace(/^(Berikut|Ini|Tentu|Baik).*?(deskripsi|tags).*?:\n?/i, '')
    .trim();
};

const cleanScriptResponse = (text: string) => {
  let clean = text.replace(/\*\*/g, '').replace(/\*/g, '');
  clean = clean
    .replace(/^Berikut adalah naskah[\s\S]*?:\n?/i, '')
    .replace(/^Tentu, ini naskah[\s\S]*?:\n?/i, '')
    .replace(/^Sesuai aturan V\d+\.\d+[\s\S]*?:\n?/i, '')
    .replace(/^Halo.*?:\n?/i, '')
    .replace(/^BABAK \d+[:\s].*?$/gim, '')
    .replace(/^SEGMEN [A-Z]+[:\s].*?$/gim, '')
    .replace(/^\(Total Word Count:.*?\)$/gim, '')
    .replace(/^Nomor \d+[:\.]\s*/gim, '')
    .replace(/^Poin \d+[:\.]\s*/gim, '')
    .replace(/^\d+[:\.]\s+/gim, '')
    .replace(/\(Visual:.*?\)/gi, '')
    .replace(/\[Visual:.*?\]/gi, '')
    .trim();
  return clean;
};

// --- EXISTING FILE TO BASE64 HELPER ---
export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const generateIdeas = async (referenceText: string, fileContents: string[], keywords: string) => {
  const filesContext = fileContents.length > 0 ? `\n\n[ISI FILE TAMBAHAN]:\n${fileContents.join('\n\n---\n\n')}` : '';
  const keywordsContext = keywords ? `\n\n[KATA KUNCI WAJIB ADA DI JUDUL/KONTEKS]: ${keywords}` : '';
  const prompt = `Referensi Utama:\n${referenceText}${filesContext}${keywordsContext}\n\nLakukan instruksi di system instruction.`;
  return generateContent(PROMPT_IDEAS, prompt, "gemini-2.0-flash");
};

export const analyzeIdea = async (idea: VideoIdea) => {
    const pointsList = idea.points.map((p, i) => `${i + 1}. ${p}`).join('\n');
    const prompt = `Judul Ide: ${idea.title}\nHook: ${idea.hook}\n\nDAFTAR POIN MENTAH:\n${pointsList}\n\nLakukan analisis poin dan berikan alternatif brutal dalam format JSON.`;
    return generateContent(PROMPT_ANALYSIS, prompt, "gemini-2.0-flash", undefined, "application/json");
};

export const generateStructureFromPoints = async (idea: VideoIdea, chosenPoints: string, targetWordCount: number) => {
  const pointsCount = chosenPoints.split('\n').filter(line => line.trim().length > 0).length;
  const prompt = `KONTEKS IDE:\nJudul: ${idea.title}\nHook Awal: ${idea.hook}\n\nDAFTAR ${pointsCount} POIN TERPILIH (WAJIB DIPAKAI SEMUA):\n${chosenPoints}\n\nTARGET TOTAL KATA NASKAH: ${targetWordCount} Kata.\n\nBuat struktur narasi lengkap (Babak 1, 2, 3) berdasarkan poin-poin tersebut. Ingat aturan V6.3: Solusi ada di dalam tiap poin Babak 2.`;
  return generateContent(PROMPT_REORDER, prompt, "gemini-2.0-flash");
};

export const generateFinalStructure = async (prevStructure: string, finalMainTitle: string, finalSubtitles: string[]) => {
  const subtitlesText = finalSubtitles.map((st, i) => `Poin ${i + 1}: ${st}`).join('\n');
  const prompt = `Struktur Dasar:\n${prevStructure}\n\nJudul Utama Final: ${finalMainTitle}\nSub-Judul Pilihan:\n${subtitlesText}\n\nBuat struktur narasi final (V6.3). Solusi terintegrasi dalam poin.`;
  return generateContent(PROMPT_FINAL_STRUCTURE, prompt, "gemini-2.0-flash");
};

export const generateScriptSection = async (finalStructure: string, sectionName: string, targetWordCount: number, totalPoints: number) => {
  let extraInstructions = "";
  const lowerSection = sectionName.toUpperCase();
  const introTarget = Math.round(targetWordCount * 0.12);
  const outroTarget = Math.round(targetWordCount * 0.08);
  const bodyTotal = targetWordCount - introTarget - outroTarget;
  const bodyPerPoint = Math.max(100, Math.round(bodyTotal / (totalPoints || 5)));

  if (lowerSection.includes("HOOK") || lowerSection.includes("BABAK 1")) {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${introTarget} Kata.\n[ATURAN BABAK 1]: Start STACCATO. No Header. Langsung Narasi.`;
  } else if (lowerSection.includes("PENUTUP") || lowerSection.includes("BABAK 3")) {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${outroTarget} Kata.\n[ATURAN BABAK 3]: No Header. Langsung Closing. Akhiri 'Ciao'.`;
  } else {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${bodyPerPoint} Kata.\n[ATURAN STRICT V6.6]: LANGSUNG BAHAS ISI. JANGAN ULANG JUDUL POIN DI AWAL KALIMAT.`;
  }

  const prompt = `Struktur Narasi Final:\n${finalStructure}\n\nPERINTAH: Tuliskan Naskah Penuh (Full Text) untuk bagian: "${sectionName}". ${extraInstructions}`;
  const response = await generateContent(PROMPT_SCRIPT_ROLE, prompt, "gemini-2.0-flash");
  return cleanScriptResponse(response);
};

export const generateDescription = async (fullScript: string, videoTitle: string) => {
  const prompt = `JUDUL VIDEO: ${videoTitle}\n\nNASKAH LENGKAP:\n${fullScript}\n\nBuatkan deskripsi YouTube.`;
  const response = await generateContent(PROMPT_DESCRIPTION, prompt, "gemini-2.0-flash");
  return cleanMetadataResponse(response);
};

export const generateTags = async (fullScript: string, videoTitle: string) => {
  const prompt = `JUDUL VIDEO: ${videoTitle}\n\nNASKAH LENGKAP:\n${fullScript}\n\nBuatkan Tags YouTube.`;
  const response = await generateContent(PROMPT_TAGS, prompt, "gemini-2.0-flash");
  return cleanMetadataResponse(response);
};


