// --- IMAGE GENERATION SERVICE PATCHED (STRICT ILMU LIDI - NO STICKMAN WORD) ---

const THUMBNAIL_STYLE_SUFFIX = "Modern 2D webcomic style, bold clean line art, stylized character design, flat colors with cel-shading, cinematic dramatic lighting, volumetric atmosphere, rim lighting, deep shadows, ambient occlusion, depth of field, sharp focus on subject, 8k resolution, high quality digital illustration.";

// New return type interface
export interface ImageGenerationResult {
    imageUrl: string;
    engineeredPrompt: string;
}

export const generateRealThumbnailImage = async (
  prompt: string,
  referenceImages: File[],
  referenceBackground: File | null,
  referenceTextStyle: File | null,
  emphasisText: string,
  normalText: string,
  actionDescription: string // NEW PARAMETER
): Promise<ImageGenerationResult> => { // Change return type
  const ai = getAIClient();
  const parts: any[] = [];

  // 1. System Prompt (REVISI: ACTION DESCRIPTION ADDED)
  const engineeredPrompt = `
    ROLE: Professional YouTube Thumbnail Artist.

    [VISUAL STYLE]:
    ${THUMBNAIL_STYLE_SUFFIX}

    [SCENE DESCRIPTION]:
    ${prompt}

    [CHARACTER ACTION - MANDATORY]:
    The character "Ilmu Lidi" MUST be doing this specific action:
    "${actionDescription}"
    (Ensure the pose and emotion match this description exactly).

    [COMPOSITION - RULE OF THIRDS]:
    1. **SPLIT LAYOUT**:
       - **LEFT SIDE**: Reserved for Text Overlay. Use Negative Space or Clean Background here.
       - **RIGHT SIDE**: Place the Character ("Ilmu Lidi") and Main Action/Monster/Object here.
    2. **TIMESTAMP SAFETY**:
       - **KEEP BOTTOM-RIGHT CORNER EMPTY**. Do not put character faces or text there.

    [SUBJECT - CHARACTER]:
    - The character is named "Ilmu Lidi".
    - **CRITICAL**: DO NOT INVENT THE CHARACTER DESIGN.
    - **MANDATORY**: You MUST use the visual traits from the provided REFERENCE IMAGES exactly.
    - If the reference looks like a stick figure, draw that. If it looks like a complex robot, draw that.
    - TRUST THE REFERENCE IMAGE ONLY.

    [TEXT OVERLAY INSTRUCTIONS - STRICT]:
    The image must include these specific text overlays embedded in the composition.

    **FULL PHRASE TO RENDER**:
    "${emphasisText} ${normalText}"
    (The text must be split into two visual parts, but read as one continuous phrase).

    **ARRANGEMENT DETAILS**:
    1. **EMPHASIS PART**: "${emphasisText}"
       - Style: Massive, Bold, High Impact.
       - Color: WHITE on RED Box/Background (Sticker style).
       - Position: LEFT SIDE (Top or Center).
    2. **NORMAL PART**: "${normalText}"
       - Style: Large, Readable, Bold Sans-Serif.
       - Color: BLACK or YELLOW (High Contrast).
       - Position: Directly below or above the Emphasis text.
       - **CRITICAL**: Must visually connect with the Emphasis text to complete the sentence (e.g., if Emphasis is "MODAL USAHA", Normal is "MENGUAP", they must be close).

    [COLOR RESTRICTIONS]:
    - Do not invent colors for objects; infer lighting/tone from the Style Suffix.
  `;
  parts.push({ text: engineeredPrompt });

  // 2. Background
  if (referenceBackground) {
    const bgBase64 = await fileToBase64(referenceBackground);
    parts.push({ text: "USE THIS BACKGROUND COMPOSITION:" });
    parts.push({ inlineData: { data: bgBase64, mimeType: referenceBackground.type } });
  }

  // 3. Characters
  if (referenceImages && referenceImages.length > 0) {
      parts.push({ text: "REFERENCE CHARACTER (USE EXACTLY):" });
      for (const file of referenceImages) {
        const base64 = await fileToBase64(file);
        parts.push({ inlineData: { data: base64, mimeType: file.type } });
      }
  }

  // 4. Text Style Reference
  if (referenceTextStyle) {
      const textBase64 = await fileToBase64(referenceTextStyle);
      parts.push({ text: "REFERENCE TEXT TYPOGRAPHY STYLE:" });
      parts.push({ inlineData: { data: textBase64, mimeType: referenceTextStyle.type } });
  }

  try {
    // Model: gemini-2.5-flash-image
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image", 
      contents: { parts },
      config: {
          // @ts-ignore
          imageGenerationConfig: {
              aspectRatio: "16:9",
              sampleCount: 1
          }
      }
    });

    // Handle Image Response (Base64 extraction)
    if (response.candidates && response.candidates[0].content.parts) {
         for (const part of response.candidates[0].content.parts) {
             if (part.inlineData && part.inlineData.data) {
                 // SUCCESS: Return image AND the prompt used
                 return {
                     imageUrl: `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`,
                     engineeredPrompt: engineeredPrompt
                 };
             }
         }
    }

    console.warn("API response ok but no image data found:", response);
    // Fallback: Return placeholder and the prompt (so user can see what was sent)
    return {
        imageUrl: "https://via.placeholder.com/1280x720/000000/FFFFFF?text=No+Image+Data+Returned",
        engineeredPrompt: engineeredPrompt + "\n\n[WARN: API returned OK but no image data found]"
    };

  } catch (error) {
     console.error("Image Gen Error:", error);
     // Error: Return placeholder and the prompt with error message
     return {
         imageUrl: "https://via.placeholder.com/1280x720/000000/FFFFFF?text=Generation+Failed+(Check+Console)",
         engineeredPrompt: engineeredPrompt + `\n\n[ERROR: Generation failed: ${error}]`
     };
  }
};

import React, { useState, useRef } from 'react';
import { TitleThumbnailPair, ScriptSection } from '../types';
import { refineImagePrompt } from '../services/geminiService';

interface Props {
  scriptSections: ScriptSection[];
  keywords: string;
  contextOverride?: string;
  onNext: (selectedPair: TitleThumbnailPair) => void;
  onBack: () => void;
  onGeneratePairs: (context: string, keywords: string, mandatoryKeywords: string, count: number, specificObject: string) => Promise<TitleThumbnailPair[]>;
  onGenerateImage: (prompt: string, refs: File[], bg: File | null, txtRef: File | null, emp: string, norm: string, actionDesc: string) => Promise<{ imageUrl: string, engineeredPrompt: string }>;
}

export const Step8TitleThumbnail: React.FC<Props> = ({ 
    scriptSections, 
    keywords: initialKeywords, 
    contextOverride,
    onNext, 
    onBack,
    onGeneratePairs,
    onGenerateImage
}) => {
  const [pairs, setPairs] = useState<TitleThumbnailPair[]>([]);
  const [isGeneratingPairs, setIsGeneratingPairs] = useState(false);
  const [isRegeneratingSingle, setIsRegeneratingSingle] = useState<Record<string, boolean>>({});

  // Inputs
  const [mandatoryKeywords, setMandatoryKeywords] = useState('');
  const [specificObject, setSpecificObject] = useState(''); // New State

  // Ref Inputs
  const [refImages, setRefImages] = useState<File[]>([]);
  const [bgImage, setBgImage] = useState<File | null>(null);
  const [textStyleImage, setTextStyleImage] = useState<File | null>(null);

  const bgInputRef = useRef<HTMLInputElement>(null);
  const charInputRef = useRef<HTMLInputElement>(null);
  const textInputRef = useRef<HTMLInputElement>(null);

  const [selectedPairId, setSelectedPairId] = useState<string | null>(null);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  // Prompt Modification State
  const [modifyingPromptId, setModifyingPromptId] = useState<string | null>(null);
  const [modificationInput, setModificationInput] = useState('');

  const getContext = () => {
      if (contextOverride) return contextOverride;
      return scriptSections.map(s => s.content).join(' ').substring(0, 3000);
  };

  const handleGeneratePairs = async () => {
      setIsGeneratingPairs(true);
      try {
          const context = getContext();
          const results = await onGeneratePairs(context, initialKeywords, mandatoryKeywords, 3, specificObject);
          setPairs(results);
          if (results.length > 0) setSelectedPairId(results[0].id);
      } catch (e) {
          alert("Gagal membuat variasi judul/thumbnail.");
      } finally {
          setIsGeneratingPairs(false);
      }
  };

  const handleRegenerateSinglePair = async (pairId: string) => {
      setIsRegeneratingSingle(prev => ({ ...prev, [pairId]: true }));
      try {
          const context = getContext();
          // Generate just 1 new idea
          const newPairs = await onGeneratePairs(context, initialKeywords, mandatoryKeywords, 1, specificObject);

          if (newPairs.length > 0) {
              const newPair = newPairs[0];
              // Update state replacing only the matching ID with the new pair
              setPairs(prev => prev.map(p => p.id === pairId ? newPair : p));

              if (selectedPairId === pairId) {
                  setSelectedPairId(newPair.id);
              }
          }
      } catch (e) {
          alert("Gagal regenerasi ide ini.");
      } finally {
          setIsRegeneratingSingle(prev => ({ ...prev, [pairId]: false }));
      }
  };

  const handleUpdatePairData = (pairId: string, field: 'emphasisText' | 'normalText' | 'prompt', value: string) => {
      setPairs(prev => prev.map(p => {
          if (p.id !== pairId) return p;
          if (field === 'prompt') {
              return { ...p, thumbnail: { ...p.thumbnail, prompt: value } };
          }
          return { ...p, thumbnail: { ...p.thumbnail, [field]: value } };
      }));
  };

  const handleRefinePrompt = async (pairId: string) => {
      if (!modificationInput.trim()) return;
      setModifyingPromptId(pairId);
      const pair = pairs.find(p => p.id === pairId);
      if (!pair) return;

      try {
          const newPrompt = await refineImagePrompt(pair.thumbnail.prompt, modificationInput);
          handleUpdatePairData(pairId, 'prompt', newPrompt);
          setModificationInput('');
      } catch (e) {
          alert("Gagal memodifikasi prompt.");
      } finally {
          setModifyingPromptId(null);
      }
  };

  const handleGenerateThumbnailImage = async (pairId: string) => {
      const pair = pairs.find(p => p.id === pairId);
      if (!pair) return;

      if (!bgImage) {
          alert("WAJIB Upload Background Referensi dulu!");
          return;
      }

      setPairs(prev => prev.map(p => p.id === pairId ? { ...p, thumbnail: { ...p.thumbnail, status: 'generating' } } : p));

      try {
          const actionDesc = pair.thumbnail.actionDescription || "Character standing in the scene.";

          // Use current state values (edited) instead of original
          const { imageUrl, engineeredPrompt } = await onGenerateImage(
              pair.thumbnail.prompt, // Use the potentially edited prompt
              refImages,
              bgImage,
              textStyleImage,
              pair.thumbnail.emphasisText, // Use edited text
              pair.thumbnail.normalText, // Use edited text
              actionDesc
          );

          setPairs(prev => prev.map(p => p.id === pairId ? { 
              ...p, 
              thumbnail: { 
                  ...p.thumbnail, 
                  status: 'success', 
                  imageUrl,
                  finalEngineeredPrompt: engineeredPrompt
              } 
          } : p));

      } catch (e) {
          console.error(e);
          setPairs(prev => prev.map(p => p.id === pairId ? { 
              ...p, 
              thumbnail: { ...p.thumbnail, status: 'error' } 
          } : p));
          alert("Gagal generate gambar. Cek koneksi atau API Key.");
      }
  };

  const handleRefImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files) setRefImages(Array.from(e.target.files));
  };

  return (
    <div className="space-y-8 pb-32 relative">
      <div className="border-b pb-6 flex justify-between items-end">
        <div>
            <h2 className="text-3xl font-black text-gray-900 tracking-tight">Judul & Visual Split Testing <span className="text-yellow-500">v7.3</span></h2>
            <p className="text-gray-500 mt-2 font-medium">
                Sistem akan membuat 3 Variasi Psikologi (Monster, Jebakan, Negasi, dll).
            </p>
        </div>
        {pairs.length > 0 && (
            <button 
                onClick={handleGeneratePairs} 
                disabled={isGeneratingPairs}
                className="text-xs font-bold text-gray-500 underline hover:text-black"
            >
                {isGeneratingPairs ? 'Regenerating...' : 'Regenerate All Ideas'}
            </button>
        )}
      </div>

      {/* 1. INPUT ASSETS SECTION */}
      <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm space-y-6">
          <div className="flex flex-col md:flex-row gap-6 justify-between items-start md:items-center border-b pb-4 mb-4">
               <div>
                   <h3 className="font-bold text-gray-800 uppercase tracking-wide text-sm">1. Konfigurasi Visual & Judul</h3>
                   <span className="text-xs text-gray-400">Upload aset dan tentukan kata kunci wajib</span>
               </div>
          </div>

          <div className="grid md:grid-cols-2 gap-6 mb-6">
              {/* Keyword Wajib Input */}
              <div className="bg-yellow-50 border border-yellow-200 p-4 rounded-xl">
                  <label className="block text-xs font-bold text-gray-700 uppercase mb-2">
                      Kata Kunci Wajib (Judul)
                  </label>
                  <input 
                      type="text" 
                      value={mandatoryKeywords}
                      onChange={(e) => setMandatoryKeywords(e.target.value)}
                      placeholder="Contoh: Korupsi, DPR"
                      className="w-full p-3 border border-yellow-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none text-sm font-bold text-gray-900 placeholder-gray-400"
                  />
                  <p className="text-[10px] text-gray-500 mt-1">*Verbatim di judul.</p>
              </div>

              {/* NEW: Specific Object Input */}
              <div className="bg-blue-50 border border-blue-200 p-4 rounded-xl">
                  <label className="block text-xs font-bold text-gray-700 uppercase mb-2">
                      Objek Spesifik Thumbnail (Opsional)
                  </label>
                  <input 
                      type="text" 
                      value={specificObject}
                      onChange={(e) => setSpecificObject(e.target.value)}
                      placeholder="Contoh: Rumah KPR, iPhone 16, Gerobak Bakso"
                      className="w-full p-3 border border-blue-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm font-bold text-gray-900 placeholder-gray-400"
                  />
                  <p className="text-[10px] text-gray-500 mt-1">*Objek ini akan dipaksa masuk ke prompt gambar.</p>
